const msg=($input.first().json.chatInput||$input.first().json.input||'').trim();
const num=msg.replace(/\s/g,'').toUpperCase();
const isNum=/^(SC|NI|OC|SO|NP|NV)?[0-9]{6,8}$/.test(num);
if(isNum)return[{json:{mode:'single',chUrl:'https://api.company-information.service.gov.uk/company/'+num,max:1,location:'',sicCodes:[]}}];
const sics=(msg.match(/\b\d{4,5}\b/g)||[]).filter(s=>+s>=1000);
const mx=(msg.match(/\b(\d+)\s*comp/i)||[])[1];
const max=Math.min(mx?+mx:25,25);
const loc=msg.replace(/\b\d{4,5}\b/g,'').replace(/\b\d+\s*comp\w*/gi,'').replace(/sic/gi,'').replace(/[,\s]+/g,' ').trim();
const qp=['company_status=active','items_per_page='+String(max)];
if(sics.length)qp.push('sic_codes='+encodeURIComponent(sics.join(',')));
if(loc)qp.push('location='+encodeURIComponent(loc));
return[{json:{mode:'sic',chUrl:'https://api.company-information.service.gov.uk/advanced-search/companies?'+qp.join('&'),sicCodes:sics,location:loc,max}}];

const src=$('Parse Input').first().json;
const d=$input.first().json;
const addr=o=>[o?.address_line_1,o?.locality,o?.postal_code].filter(Boolean).join(', ');
let list=[];
if(src.mode==='single'){
  if(d.company_number)list=[{companyNumber:d.company_number,companyName:d.company_name||'',address:addr(d.registered_office_address),sicCodes:d.sic_codes||[],incorporated:d.date_of_creation||''}];
}else{
  list=(d.items||[]).map(c=>({companyNumber:c.company_number,companyName:c.company_name||'',address:addr(c.registered_office_address),sicCodes:c.sic_codes||[],incorporated:c.date_of_creation||''}));
}
return list.slice(0,src.max||25).map(c=>({json:c}));

return $input.all().map((item,i)=>{
  const co=$('Normalize Results').all()[i].json;
  const dirs=(item.json.items||[]).filter(o=>!o.resigned_on).map(o=>o.name+' ('+o.officer_role+')').slice(0,3);
  return{json:{...co,directors:dirs.join('; ')||'N/A'}};
});

return $input.all().map((item,i)=>{
  const co=$('Add Officers').all()[i].json;
  const f=(item.json.items||[])[0];
  const pdfUrl=f?.links?.document_metadata?f.links.document_metadata+'/content':null;
  return{json:{...co,pdfUrl,filingDate:f?.date||null,filingType:f?.type||null}};
});

return $input.all().map((item,i)=>{
  const co=$('Add Filing URL').all()[i].json;
  const txt=item.json.error?'':(item.json.text||item.json.data||'');
  return{json:{...co,pdfText:String(txt).substring(0,2000)}};
});

return $input.all().map((item,i)=>{
  const co=$('Merge PDF').all()[i].json;
  const web=(item.json.results||[]).slice(0,3).map(r=>r.title+': '+(r.content||'')).join('
');
