Return: {"score":1-10,"products":["product names"],"summary":"2 sentences","size":"micro/small/medium/large","approach":"who to contact and angle","flags":"red flags or none"}';
  const body=JSON.stringify({model:'qwen3.6:27b',prompt,stream:false,format:'json'});
