const src=$('Parse Input').first().json;
const all=$input.all().map(i=>i.json).sort((a,b)=>b.aiScore-a.aiScore);
const leads=all.filter(c=>c.aiScore>=5);
const failed=all.filter(c=>c.aiScore<5);
const col=s=>s>=8?'#27ae60':s>=6?'#e67e22':'#e74c3c';
const ch=n=>'https://find-and-update.company-information.service.gov.uk/company/'+n;
const date=new Date().toLocaleDateString('en-GB');
const subj='Portland Fuel Leads — '+leads.length+' leads | '+(src.location||'Company lookup')+' | '+date;
const evalRows=all.map(c=>'<tr><td style="padding:8px;border-bottom:1px solid #ddd"><strong><a href="'+ch(c.companyNumber)+'" target="_blank">'+c.companyName+'</a></strong><br><small style="color:#666">'+c.companyNumber+'</small></td><td style="padding:8px;border-bottom:1px solid #ddd;text-align:center"><span style="font-size:18px;font-weight:bold;color:'+col(c.aiScore)+'">'+c.aiScore+'/10</span></td><td style="padding:8px;border-bottom:1px solid #ddd">'+(c.aiProducts||[]).join(', ')+'</td><td style="padding:8px;border-bottom:1px solid #ddd;text-align:center"><span style="background:'+(c.aiScore>=5?'#27ae60':'#e74c3c')+';color:#fff;padding:3px 8px;border-radius:3px;font-size:11px">'+(c.aiScore>=5?'PASS':'FAIL')+'</span></td></tr>').join('');
const detailRows=leads.map(c=>'<tr><td style="padding:10px;border-bottom:1px solid #ddd"><strong><a href="'+ch(c.companyNumber)+'" target="_blank">'+c.companyName+'</a></strong><br><small>'+c.address+'</small><br><small>Directors: '+c.directors+'</small></td><td style="padding:10px;border-bottom:1px solid #ddd;text-align:center"><span style="font-size:22px;font-weight:bold;color:'+col(c.aiScore)+'">'+c.aiScore+'</span></td><td style="padding:10px;border-bottom:1px solid #ddd">'+(c.aiProducts||[]).join(', ')+'</td><td style="padding:10px;border-bottom:1px solid #ddd">'+c.aiSummary+'<br><em>'+c.aiApproach+'</em>'+(c.aiFlags&&c.aiFlags!=='none'?'<br><b style="color:red">'+c.aiFlags+'</b>':'')+'</td></tr>').join('');
const qualSection=leads.length?'<h3 style="color:#2c3e50;margin-top:30px">Qualified Leads — Full Detail</h3><table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse"><thead><tr style="background:#2c3e50;color:#fff"><th style="padding:10px;text-align:left">Company</th><th style="padding:10px;width:60px">Score</th><th style="padding:10px;width:180px">Products</th><th style="padding:10px;text-align:left">Assessment</th></tr></thead><tbody>'+detailRows+'</tbody></table>':'<p style="color:#e74c3c;margin-top:20px"><b>No companies scored 5 or above.</b></p>';
const html='<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:950px;margin:0 auto"><h2 style="color:#2c3e50">Portland Fuel Lead Digest</h2><p><b>'+leads.length+' passed</b> | <b>'+failed.length+' failed</b> | threshold: 5/10 | '+(src.location||'')+' | SIC: '+(src.sicCodes||[]).join(', ')+' | '+date+'</p><h3 style="color:#2c3e50">All Companies Evaluated ('+all.length+')</h3><table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse"><thead><tr style="background:#2c3e50;color:#fff"><th style="padding:8px;text-align:left">Company</th><th style="padding:8px;width:60px">Score</th><th style="padding:8px;width:180px">Products</th><th style="padding:8px;width:60px">Result</th></tr></thead><tbody>'+evalRows+'</tbody></table>'+qualSection+'<p style="color:#999;font-size:11px">Generated '+new Date().toISOString()+' via n8n / amelai</p></body></html>';
return[{json:{subject:subj,htmlBody:html}}];
